import{_ as d,o as e,c as a,ag as o}from"./chunks/framework.BmLMQRXF.js";const m=JSON.parse('{"title":"의존성 목록","description":"","frontmatter":{},"headers":[],"relativePath":"ko-kr/manage/dependencies.md","filePath":"ko-kr/manage/dependencies.md","lastUpdated":1783338759000}'),c={name:"ko-kr/manage/dependencies.md"};function s(i,t,l,r,n,p){return e(),a("div",null,t[0]||(t[0]=[o('<h1 id="의존성-목록" tabindex="-1">의존성 목록 <a class="header-anchor" href="#의존성-목록" aria-label="Permalink to &quot;의존성 목록&quot;">​</a></h1><p>이 목록은 asdf 버전 0.16.0 이상을 위한 것입니다. 이전 버전의 asdf는 추가적인 의존성이 필요합니다.</p><p>asdf 자체는 다음이 설치되어 있어야 합니다:</p><ul><li>Bash 버전 <code>3.2.48</code></li><li>Git 버전 <code>1.7.7.2</code></li></ul><div class="tip custom-block"><p class="custom-block-title">노트</p><p>asdf 플러그인은 사용하기 전에 추가적인 프로그램의 설치가 필요할 수 있습니다. 플러그인을 설치하기 전에 플러그인의 문서를 읽고 해당 플러그인의 모든 의존성이 설치되어 있는지 확인하세요.</p></div><h2 id="설치" tabindex="-1">설치 <a class="header-anchor" href="#설치" aria-label="Permalink to &quot;설치&quot;">​</a></h2><p>asdf의 의존성을 직접 설치해야 한다면 아래에서 당신의 운영체제에 맞는 명령어를 실행하세요.</p><table tabindex="0"><thead><tr><th>운영체제</th><th>패키지 매니저</th><th>명령어</th></tr></thead><tbody><tr><td>linux</td><td>Aptitude</td><td><code>apt install git bash</code></td></tr><tr><td>linux</td><td>DNF</td><td><code>dnf install git bash</code></td></tr><tr><td>linux</td><td>Pacman</td><td><code>pacman -S git bash</code></td></tr><tr><td>linux</td><td>Zypper</td><td><code>zypper install git bash</code></td></tr><tr><td>macOS</td><td>Homebrew</td><td><code>brew install coreutils git bash</code></td></tr><tr><td>macOS</td><td>Spack</td><td><code>spack install coreutils git bash</code></td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">노트</p><p>시스템 설정에 의해 <code>sudo</code>가 필요할 수 있습니다.</p></div>',9)]))}const u=d(c,[["render",s]]);export{m as __pageData,u as default};
